import { useState, useEffect, useRef } from "react";

const API = "http://localhost:8000";

const C = {
  bg: "#040407", surface: "#08080f", border: "#12121e",
  red: "#ff3355", blue: "#3d8bff", green: "#00e676",
  yellow: "#ffd740", orange: "#ff9100", dim: "#3a3a55",
  muted: "#666680", text: "#c8c8e0", card: "#0c0c18",
};

const SEV = { CRITICAL: C.red, HIGH: C.orange, MEDIUM: C.yellow, LOW: C.green };
const OWASP_COLORS = {
  "LLM01": "#ff3355", "LLM02": "#ff6b35", "LLM06": "#ffd740",
  "LLM08": "#3d8bff", "LLM09": "#b44dff",
};

const Badge = ({ label, color }) => (
  <span style={{ background: color + "22", color, border: `1px solid ${color}44`, borderRadius: 4, padding: "2px 8px", fontSize: 10, letterSpacing: 1, fontWeight: 700 }}>{label}</span>
);
const Card = ({ children, accent, style = {} }) => (
  <div style={{ background: C.surface, border: `1px solid ${accent ? accent + "33" : C.border}`, borderRadius: 8, padding: 16, ...style }}>{children}</div>
);
const Label = ({ children }) => (
  <div style={{ fontSize: 9, letterSpacing: 2, color: C.dim, textTransform: "uppercase", marginBottom: 8 }}>{children}</div>
);
const Mono = ({ children, color = C.muted, size = 11 }) => (
  <span style={{ fontFamily: "monospace", fontSize: size, color }}>{children}</span>
);

async function downloadPDF(report) {
  if (!window.jspdf) {
    await new Promise((resolve, reject) => {
      const script = document.createElement("script");
      script.src = "https://cdnjs.cloudflare.com/ajax/libs/jspdf/2.5.1/jspdf.umd.min.js";
      script.onload = resolve;
      script.onerror = reject;
      document.head.appendChild(script);
    });
  }
  const { jsPDF } = window.jspdf;
  const doc = new jsPDF({ orientation: "portrait", unit: "mm", format: "a4" });
  const W = 210, margin = 20, maxW = W - margin * 2;
  let y = 20;
  const sevColor = { CRITICAL: [255,51,85], HIGH: [255,145,0], MEDIUM: [255,215,64], LOW: [0,230,118] };
  const sev = report.verdict?.severity || "UNKNOWN";
  const color = sevColor[sev] || [100,100,100];
  const blocked = report.defense?.blocked;

  doc.setFillColor(4,4,7);
  doc.rect(0,0,W,30,"F");
  doc.setTextColor(255,51,85);
  doc.setFontSize(18);
  doc.setFont("helvetica","bold");
  doc.text("GEMMA", margin, 18);
  doc.setTextColor(255,255,255);
  doc.text("SHIELD", margin+30, 18);
  doc.setFontSize(9);
  doc.setTextColor(100,100,128);
  doc.setFont("helvetica","normal");
  doc.text("AI Security Assessment Report", margin, 25);
  doc.text(`Report ID: ${report.report_id}`, W-margin, 18, {align:"right"});
  doc.text(`${new Date(report.generated_at).toLocaleString()}`, W-margin, 25, {align:"right"});
  y = 40;

  doc.setFillColor(...color, 30);
  doc.roundedRect(margin, y, maxW, 22, 3, 3, "F");
  doc.setDrawColor(...color);
  doc.setLineWidth(0.5);
  doc.roundedRect(margin, y, maxW, 22, 3, 3, "S");
  doc.setFont("helvetica","bold");
  doc.setFontSize(22);
  doc.setTextColor(...color);
  doc.text(`${report.verdict?.cvss_like_score}/10`, margin+6, y+14);
  doc.setFontSize(11);
  doc.text(sev, margin+40, y+10);
  doc.setFont("helvetica","normal");
  doc.setFontSize(9);
  doc.setTextColor(180,180,200);
  doc.text("CVSS-LIKE SCORE", margin+6, y+19);
  const statusColor = blocked ? [0,230,118] : [255,51,85];
  doc.setFontSize(13);
  doc.setFont("helvetica","bold");
  doc.setTextColor(...statusColor);
  doc.text(blocked ? "BLOCKED" : "BREACHED", W-margin-6, y+10, {align:"right"});
  doc.setFontSize(9);
  doc.setFont("helvetica","normal");
  doc.setTextColor(100,100,128);
  doc.text(`Patch Priority: ${report.verdict?.patch_priority || "N/A"}`, W-margin-6, y+18, {align:"right"});
  y += 30;

  const sectionHeader = (title) => {
    doc.setFillColor(12,12,24);
    doc.rect(margin, y, maxW, 7, "F");
    doc.setFont("helvetica","bold");
    doc.setFontSize(8);
    doc.setTextColor(100,100,128);
    doc.text(title, margin+3, y+4.5);
    y += 10;
  };
  const wrappedText = (text, x, maxWidth, lineHeight=5) => {
    if (!text) return;
    const lines = doc.splitTextToSize(String(text), maxWidth);
    doc.text(lines, x, y);
    y += lines.length * lineHeight + 2;
  };

  sectionHeader("EXECUTIVE SUMMARY");
  doc.setFont("helvetica","normal");
  doc.setFontSize(10);
  doc.setTextColor(200,200,224);
  wrappedText(report.executive_summary, margin, maxW);
  y += 2;

  sectionHeader("TARGET & CLASSIFICATION");
  doc.setFontSize(9);
  doc.setTextColor(160,160,190);
  doc.text("Target System:", margin, y);
  doc.setTextColor(200,200,224);
  doc.text(report.target_system || "N/A", margin+30, y);
  y += 6;
  if (report.owasp_category?.id) {
    const owaspColor = {LLM01:[255,51,85],LLM02:[255,107,53],LLM06:[255,215,64],LLM08:[61,139,255],LLM09:[180,77,255]};
    const oc = owaspColor[report.owasp_category.id] || [100,100,128];
    doc.setFillColor(...oc, 40);
    doc.roundedRect(margin, y, 80, 7, 1, 1, "F");
    doc.setTextColor(...oc);
    doc.setFont("helvetica","bold");
    doc.setFontSize(8);
    doc.text(`${report.owasp_category.id}: ${report.owasp_category.name}`, margin+3, y+4.5);
    y += 12;
  }

  sectionHeader("ATTACK DETAILS");
  const atk = report.attack || {};
  [["Type", atk.type?.replace(/_/g," ").toUpperCase()],["Technique",atk.technique],["Target Weakness",atk.target_weakness],["Severity",atk.severity],["Stealth Score",`${atk.stealth_score}/10`]].forEach(([k,v]) => {
    if (!v) return;
    doc.setFontSize(8); doc.setFont("helvetica","bold"); doc.setTextColor(100,100,128);
    doc.text(`${k}:`, margin, y);
    doc.setFont("helvetica","normal"); doc.setTextColor(200,200,224);
    const lines = doc.splitTextToSize(String(v), maxW-35);
    doc.text(lines, margin+35, y);
    y += lines.length * 4.5 + 1;
  });
  y += 3;

  sectionHeader("ATTACK PROMPT");
  doc.setFillColor(8,8,15);
  const promptLines = doc.splitTextToSize(atk.prompt || "N/A", maxW-6);
  const promptH = promptLines.length * 4.5 + 6;
  doc.rect(margin, y, maxW, promptH, "F");
  doc.setFont("courier","normal"); doc.setFontSize(8); doc.setTextColor(180,180,200);
  doc.text(promptLines, margin+3, y+4.5);
  y += promptH + 5;

  if (y > 240) { doc.addPage(); y = 20; }

  sectionHeader("VULNERABILITY");
  doc.setFont("helvetica","normal"); doc.setFontSize(9); doc.setTextColor(200,200,224);
  wrappedText(report.verdict?.vulnerability_label, margin, maxW);

  sectionHeader("DEFENSE REASONING");
  (report.defense?.reasoning || []).forEach((step, i) => {
    doc.setFont("helvetica","bold"); doc.setFontSize(8); doc.setTextColor(61,139,255);
    doc.text(`${i+1}.`, margin, y);
    doc.setFont("helvetica","normal"); doc.setTextColor(160,160,190);
    const lines = doc.splitTextToSize(step, maxW-8);
    doc.text(lines, margin+6, y);
    y += lines.length * 4.5 + 2;
    if (y > 260) { doc.addPage(); y = 20; }
  });
  y += 3;

  sectionHeader("RECOMMENDATION");
  doc.setFont("helvetica","normal"); doc.setFontSize(9); doc.setTextColor(200,200,224);
  wrappedText(report.verdict?.recommendation, margin, maxW);
  y += 3;

  if (y > 240) { doc.addPage(); y = 20; }

  sectionHeader("TRACEABILITY");
  const tr = report.traceability || {};
  [["Model",tr.model],["Source",tr.source],["Attacker",tr.attacker_latency_ms?`${tr.attacker_latency_ms}ms`:"N/A"],["Target",tr.target_latency_ms?`${tr.target_latency_ms}ms`:"N/A"],["Defender",tr.defender_latency_ms?`${tr.defender_latency_ms}ms`:"N/A"],["Judge",tr.judge_latency_ms?`${tr.judge_latency_ms}ms`:"N/A"],["Total",tr.total_latency_ms?`${(tr.total_latency_ms/1000).toFixed(1)}s`:"N/A"]].forEach(([k,v]) => {
    if (!v) return;
    doc.setFontSize(8); doc.setFont("helvetica","bold"); doc.setTextColor(100,100,128);
    doc.text(`${k}:`, margin, y);
    doc.setFont("helvetica","normal"); doc.setTextColor(0,230,118);
    doc.text(String(v), margin+30, y);
    y += 5;
  });

  const pageCount = doc.internal.getNumberOfPages();
  for (let i = 1; i <= pageCount; i++) {
    doc.setPage(i);
    doc.setFillColor(4,4,7);
    doc.rect(0,287,W,10,"F");
    doc.setFont("helvetica","normal"); doc.setFontSize(7); doc.setTextColor(60,60,80);
    doc.text("GemmaShield v2.1 · Powered by Gemma 4 via Ollama · All inference run locally", margin, 293);
    doc.text(`Page ${i} of ${pageCount}`, W-margin, 293, {align:"right"});
  }

  doc.save(`gemmashield-report-${report.report_id}.pdf`);
}

